if __name__ == '__main__':
    it = iter(sys.stdin.read().splitlines())
    try:
        n = int(next(it))
        root = TreeNode(int(next(it)))
        nodes = [root]
        for _ in range(n - 1):
            node = nodes.pop(0)
            left_val = int(next(it))
